from pathlib import Path

from docx import Document
from docx.enum.section import WD_ORIENT
from docx.enum.style import WD_STYLE_TYPE
from docx.enum.text import WD_ALIGN_PARAGRAPH
from docx.oxml import OxmlElement
from docx.oxml.ns import qn
from docx.shared import Cm, Pt, RGBColor


OUTPUT = Path("docs") / "Ручное_тестирование_BudgetBasket.docx"


def shade(cell, color: str) -> None:
    properties = cell._tc.get_or_add_tcPr()
    shading = OxmlElement("w:shd")
    shading.set(qn("w:fill"), color)
    properties.append(shading)


def set_cell_text(cell, value: str, bold: bool = False) -> None:
    cell.text = ""
    run = cell.paragraphs[0].add_run(value)
    run.bold = bold
    run.font.size = Pt(9)


def add_test(doc: Document, test: dict) -> None:
    doc.add_heading(f"{test['id']} — {test['title']}", level=2)
    table = doc.add_table(rows=0, cols=2)
    table.style = "Table Grid"
    for label, value in (
        ("Роль", test["role"]),
        ("Предусловия", test["pre"]),
        ("Шаги", "\n".join(f"{index + 1}. {step}" for index, step in enumerate(test["steps"]))),
        ("Ожидаемый результат", "\n".join(f"• {result}" for result in test["expected"])),
        ("Фактический результат", "____________________________________________________________"),
        ("Статус", "☐ Пройден   ☐ Не пройден   ☐ Заблокирован   ☐ Не применимо"),
    ):
        cells = table.add_row().cells
        set_cell_text(cells[0], label, True)
        set_cell_text(cells[1], value)
        shade(cells[0], "EAF2F8")
        cells[0].width = Cm(4.1)
        cells[1].width = Cm(13.4)
    paragraph = doc.add_paragraph()
    run = paragraph.add_run("Доработки по результатам теста: ")
    run.bold = True
    paragraph.add_run("________________________________________________________________________________\n"
                      "________________________________________________________________________________")
    paragraph.paragraph_format.space_after = Pt(10)


