def main() -> None:
    doc = Document()
    section = doc.sections[0]
    section.top_margin = Cm(1.5)
    section.bottom_margin = Cm(1.5)
    section.left_margin = Cm(1.6)
    section.right_margin = Cm(1.6)

    normal = doc.styles["Normal"]
    normal.font.name = "Arial"
    normal._element.rPr.rFonts.set(qn("w:eastAsia"), "Arial")
    normal.font.size = Pt(10)
    for style_name in ("Title", "Heading 1", "Heading 2"):
        style = doc.styles[style_name]
        style.font.name = "Arial"
        style._element.rPr.rFonts.set(qn("w:eastAsia"), "Arial")
        style.font.color.rgb = RGBColor(31, 78, 121)

    title = doc.add_heading("BudgetBasket", 0)
    title.alignment = WD_ALIGN_PARAGRAPH.CENTER
    subtitle = doc.add_paragraph("Чек-лист ручного функционального тестирования и проверки адаптивности")
    subtitle.alignment = WD_ALIGN_PARAGRAPH.CENTER
    subtitle.runs[0].bold = True
    doc.add_paragraph("Версия документа: 1.0    Дата подготовки: 13.07.2026    Статус: для выполнения")

    doc.add_heading("Назначение и правила заполнения", level=1)
    doc.add_paragraph("Документ покрывает пользовательский интерфейс и ключевые бизнес-сценарии BudgetBasket. Каждый тест выполняйте на подготовленном стенде. После выполнения отметьте статус, кратко зафиксируйте фактический результат и обязательно заполните блок «Доработки по результатам теста» — даже если доработки не требуются (укажите «не требуются»).")
    doc.add_paragraph("Рекомендуемые окружения: Google Chrome или Microsoft Edge актуальной версии; desktop 1440×900 и 1024×768; tablet 768×1024; mobile 375×667 и 320×568. Проверяйте также масштаб браузера 200%.")

    doc.add_heading("Подготовка тестового стенда", level=1)
    preparation = [
        "Запустить стек: docker compose up -d --build.",
        "Проверить сервисы: GET /health, GET /health/db и готовность file_guard.",
        "Использовать тестовые учётные записи: admin/admin, economist/economist, employee/employee.",
        "Подготовить тестовые PDF, PNG/JPG, DOCX, XLSX, а также пустой, неподдерживаемый и крупный файл.",
        "Для сценариев прав доступа подготовить минимум два модуля, ответственного сотрудника и экономиста, назначенного только на один из модулей.",
    ]
    for item in preparation:
        doc.add_paragraph(item, style="List Bullet")

    doc.add_heading("Легенда статусов", level=1)
    legend = doc.add_table(rows=1, cols=2)
    legend.style = "Table Grid"
    for cell, text in zip(legend.rows[0].cells, ("Статус", "Значение")):
        set_cell_text(cell, text, True)
        shade(cell, "1F4E79")
        for run in cell.paragraphs[0].runs:
            run.font.color.rgb = RGBColor(255, 255, 255)
    for status, meaning in (("Пройден", "Фактический результат соответствует ожидаемому."), ("Не пройден", "Есть дефект; описать его и необходимую доработку."), ("Заблокирован", "Тест невозможно выполнить; указать причину."), ("Не применимо", "Сценарий не относится к текущему стенду; указать основание.")):
        cells = legend.add_row().cells
        set_cell_text(cells[0], status)
        set_cell_text(cells[1], meaning)

    grouped = [
        ("1. Базовая работа, авторизация и профиль", ("GEN-", "AUTH-", "PROFILE-")),
        ("2. Управление пользователями, оргструктурой и НСИ", ("ACL-", "USERS-", "UNITS-", "CAT-")),
        ("3. Заявки, бюджетные строки и файлы", ("REQ-", "ITEM-", "FILE-")),
        ("4. Согласование, экспорт и сводка", ("FLOW-", "CONTACT-", "EXPORT-", "DASH-", "UI-")),
        ("5. Адаптивность и базовая доступность", "RESP-"),
    ]
    all_tests = tests()
    for heading, prefixes in grouped:
        doc.add_page_break()
        doc.add_heading(heading, level=1)
        prefixes = (prefixes,) if isinstance(prefixes, str) else prefixes
        for test in (test for test in all_tests if test["id"].startswith(prefixes)):
            add_test(doc, test)

    doc.add_page_break()
    doc.add_heading("Итог выполнения", level=1)
    summary = doc.add_table(rows=5, cols=2)
    summary.style = "Table Grid"
    for row, label in zip(summary.rows, ("Всего тестов", "Пройдено", "Не пройдено", "Заблокировано", "Не применимо")):
        set_cell_text(row.cells[0], label, True)
        set_cell_text(row.cells[1], "")
        shade(row.cells[0], "EAF2F8")
    doc.add_paragraph("Общий вывод / перечень критичных доработок:")
    doc.add_paragraph("________________________________________________________________________________\n" * 5)
    doc.add_paragraph("Тестировщик: ____________________    Дата: ______________    Подпись: ____________________")

    OUTPUT.parent.mkdir(parents=True, exist_ok=True)
    doc.save(OUTPUT)
    print(f"Created: {OUTPUT.resolve()}")


if __name__ == "__main__":
    main()
